CREATE VIEW `ads_alg_cd_video_shortvideo_user_predict_view` (`event_name` COMMENT "事件名称", `event_time` COMMENT "事件时间", `event_time_add` COMMENT "事件时间(加8小时后的)", `account_id` COMMENT "用户ID", `predic` COMMENT "price/ltv/loss(从reqstr中获取)", `reqstr` COMMENT "请求字符串", `extend_map` COMMENT "扩展map", `feature_map` COMMENT "特征map", `result` COMMENT "返回结果", `dt` COMMENT "日期(事件时间加8小时后的)")
COMMENT "算法日志-事件-shortvideo_user_predict" AS SELECT `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_name`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time`, hours_add(`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time`, 8) AS `event_time_add`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`account_id`, get_json_string(`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`reqstr`, '$.predict') AS `predic`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`reqstr`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`extend_map`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`feature_map`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`result`, date(hours_add(`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time`, 8)) AS `dt`
FROM `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`
WHERE (`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`dt` < '2024-03-20') AND ((date(hours_add(`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time`, 8))) < '2024-03-20') UNION ALL SELECT `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_name`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time` AS `event_time_add`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`account_id`, get_json_string(`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`reqstr`, '$.predict') AS `predic`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`reqstr`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`extend_map`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`feature_map`, `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`result`, date(`ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`event_time`) AS `dt`
FROM `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`
WHERE `ods_log`.`ods_alg_cd_video_shortvideo_user_predict`.`dt` >= '2024-03-20';